15	/// A tracing subscriber layer that forwards formatted log records to a channel.
16	struct ChannelLayer {
17	    tx: mpsc::SyncSender<String>,
18	}
19	
20	impl<S> tracing_subscriber::Layer<S> for ChannelLayer
21	where
22	    S: tracing::Subscriber,
23	{
24	    fn on_event(
25	        &self,
26	        event: &tracing::Event<'_>,
27	        _ctx: tracing_subscriber::layer::Context<'_, S>,
28	    ) {
29	        let mut visitor = MessageVisitor(String::new());
30	        event.record(&mut visitor);
31	        let line = format!("[{}] {}", event.metadata().level(), visitor.0);
32	        // Non-blocking send — drop if buffer full to avoid blocking the UI thread.
33	        let _ = self.tx.try_send(line);
34	    }
35	}
