37	struct MessageVisitor(String);
38	
39	impl tracing::field::Visit for MessageVisitor {
40	    fn record_str(&mut self, field: &tracing::field::Field, value: &str) {
41	        if field.name() == "message" {
42	            self.0 = value.to_string();
43	        }
44	    }
45	    fn record_debug(&mut self, field: &tracing::field::Field, value: &dyn std::fmt::Debug) {
46	        if field.name() == "message" {
47	            self.0 = format!("{value:?}");
48	        }
49	    }
50	}
