208	impl eframe::App for VibeAttackConfigApp {
209	    fn ui(&mut self, ui: &mut egui::Ui, _frame: &mut eframe::Frame) {
210	        let ctx = ui.ctx().clone();
211	
212	        // Honour "Open Config" requests from the tray.
213	        if self.tray.as_ref().is_some_and(|t| t.take_open_request()) {
214	            ctx.send_viewport_cmd(egui::ViewportCommand::Focus);
215	        }
216	
217	        // Repaint at ~10Hz for mic level updates when in main config view.
218	        if self.first_run.is_setup_complete() {
219	            ctx.request_repaint_after(std::time::Duration::from_millis(100));
220	        }
221	
222	        // Repaint faster while PTT capture thread is listening.
223	        if self.ptt.listening {
224	            ctx.request_repaint_after(std::time::Duration::from_millis(50));
225	        }
226	
227	        // Repaint while model download is in progress.
228	        if self.dl.is_running() {
229	            ctx.request_repaint_after(std::time::Duration::from_millis(250));
230	        }
231	
232	        // Repaint while uinput setup actions are running.
233	        use vibe_attack::ui::wizard::SetupActionStatus;
234	        if matches!(self.uinput.modprobe, SetupActionStatus::Running)
235	            || matches!(self.uinput.usermod, SetupActionStatus::Running)
236	        {
237	            ctx.request_repaint_after(std::time::Duration::from_millis(200));
238	        }
239	
240	        // Drain log channel.
241	        while let Ok(line) = self.log_rx.try_recv() {
242	            self.config.add_log_line(line);
243	        }
244	
245	        // Update mic level from atomic.
246	        self.config.mic_level = self.mic.current_level();
247	        self.config.mic_no_device = self.mic.no_device;
248	
249	        // Detect wizard completion and load profiles + start mic thread.
250	        if self.setup_just_completed {
251	            self.setup_just_completed = false;
252	            self.config.profiles = load_profiles();
253	            self.mic = spawn_mic_level_thread();
254	        }
255	
256	        ui.heading("Vibe Attack");
257	        ui.separator();
258	
259	        let was_incomplete = !self.first_run.is_setup_complete();
260	
261	        if !self.first_run.is_setup_complete() {
262	            show_wizard(
263	                ui,
264	                &mut self.first_run,
265	                &mut self.ptt,
266	                &mut self.dl,
267	                &mut self.uinput,
268	                self.config_example_contents,
269	                self.hd2_profile_contents,
270	            );
271	            // Detect transition to complete
272	            if was_incomplete && self.first_run.is_setup_complete() {
273	                self.setup_just_completed = true;
274	            }
275	        } else {
276	            show_main_config(ui, &self.config);
277	        }
278	    }
279	}
