281	fn show_main_config(ui: &mut egui::Ui, config: &ConfigApp) {
282	    // Mic level
283	    ui.horizontal(|ui| {
284	        ui.label("Mic:");
285	        if config.mic_no_device {
286	            ui.label("no device");
287	        } else {
288	            ui.add(
289	                egui::ProgressBar::new(config.mic_level.clamp(0.0, 1.0))
290	                    .desired_width(200.0)
291	                    .show_percentage(),
292	            );
293	        }
294	    });
295	
296	    ui.add_space(8.0);
297	
298	    // Profiles
299	    ui.label(format!("Profiles ({})", config.profile_count()));
300	    if config.profiles.is_empty() {
301	        ui.weak("No profiles found in ~/.config/vibe-attack/profiles/");
302	    } else {
303	        for name in &config.profiles {
304	            let is_active = config.active_profile.as_deref() == Some(name.as_str());
305	            let _ = ui.selectable_label(is_active, name.as_str());
306	        }
307	    }
308	
309	    ui.separator();
310	    ui.label("Log:");
311	    egui::ScrollArea::vertical()
312	        .auto_shrink([false, false])
313	        .stick_to_bottom(true)
314	        .show(ui, |ui| {
315	            for line in &config.log_lines {
316	                ui.monospace(line.as_str());
317	            }
318	        });
319	}
