10	/// Pure-logic state for the configuration application window.
11	pub struct ConfigApp {
12	    /// Available profile names loaded from the XDG profiles directory.
13	    pub profiles: Vec<String>,
14	    /// Name of the currently active profile, or `None` when no profile is loaded.
15	    pub active_profile: Option<String>,
16	    /// Recent log lines displayed in the UI; capped at [`MAX_LOG_LINES`].
17	    pub log_lines: Vec<String>,
18	    /// Current microphone input level (0.0–1.0), updated by the audio thread.
19	    pub mic_level: f32,
20	    /// True when no audio input device is available (shows a warning in the UI).
21	    pub mic_no_device: bool,
22	    /// Current activation mode (PTT or Wake).
23	    pub mode: ActivationMode,
24	    /// Confidence threshold as a 0–100 integer (converted from/to f32 at I/O boundaries).
25	    pub threshold_pct: u8,
26	    /// Selected audio input device name, or `None` to use the system default.
27	    pub input_device: Option<String>,
28	    /// PTT key binding string (e.g. "KEY_F13").
29	    pub ptt_binding: String,
30	    /// Status bar message surfaced to the UI after save or error.
31	    pub status_message: Option<String>,
32	    /// True when the daemon is reachable (polled each frame).
33	    pub daemon_running: bool,
34	}
