91	/// Load config from disk into `app` state and return the full `Config` for the caller to cache.
92	///
93	/// Calls `crate::config::load`, applies the result via `apply_from_config`, and returns the
94	/// loaded `Config` so that T03 can retain it for subsequent saves without re-reading the file.
95	pub fn load_config_into_app(
96	    app: &mut ConfigApp,
97	    path_override: Option<&std::path::Path>,
98	) -> anyhow::Result<Config> {
99	    let cfg = crate::config::load(path_override)?;
100	    app.apply_from_config(&cfg);
101	    Ok(cfg)
102	}
